    "case_id": "CASO-LIM-039-T1B",
    "name": "ranker",
    "ver": "2.1.0",
    "owner": "ml-risk",
    "breaking": True,
    "bump": "major",
}
invalid = {**valid, "bump": "minor"}
incomplete = {k: v for k, v in valid.items() if k != "owner"}
print(assess(valid), assess(invalid), assess(incomplete))

